"use client";
import React, { useState, useEffect, useRef } from "react";
import Link from "next/link";

const IMGS = {
  seashell: "data:image/png;base64,",
  starfish: "data:image/png;base64,",
  crab: "data:image/png;base64,",
  anchor: "data:image/png;base64,",
  coconut: "data:image/png;base64,",
  lantern: "data:image/png;base64,",
  compass: "data:image/png;base64,",
  driftwood: "data:image/png;base64,",
  flame: "data:image/png;base64,",
};

const PUZZLES = [
  {id:"item-flame",     word:"FLAME",     sc:"MEALF",    img:IMGS.flame,     hint:"Flickers in the fireplace"},
  {id:"item-seashell",  word:"SEASHELL",  sc:"LSAHSLEE", img:IMGS.seashell,  hint:"Found along the shoreline"},
  {id:"item-starfish",  word:"STARFISH",  sc:"TSAFRISH", img:IMGS.starfish,  hint:"Five arms, one star"},
  {id:"item-crab",      word:"CRAB",      sc:"RACB",     img:IMGS.crab,      hint:"Scuttles sideways on the sand"},
  {id:"item-anchor",    word:"ANCHOR",    sc:"HORANC",   img:IMGS.anchor,    hint:"Keeps the boat in place"},
  {id:"item-coconut",   word:"COCONUT",   sc:"TUCONOC",  img:IMGS.coconut,   hint:"Tropical fruit with milk inside"},
  {id:"item-lantern",   word:"LANTERN",   sc:"RNLATEN",  img:IMGS.lantern,   hint:"Lights the evening porch"},
  {id:"item-compass",   word:"COMPASS",   sc:"SSOMAPC",  img:IMGS.compass,   hint:"Always finds north"},
  {id:"item-driftwood", word:"DRIFTWOOD", sc:"DOOWFTIRD",img:IMGS.driftwood, hint:"Shaped by waves and time"},
];

const SKY = [
  "linear-gradient(to bottom,#1565c0,#90caf9)",
  "linear-gradient(to bottom,#f57c00,#ffb74d)",
  "linear-gradient(to bottom,#e91e63,#ff8a80)",
  "linear-gradient(to bottom,#311b92,#7442c8)",
];

const SAVE_KEY = "beachCottageV7";

export default function BeachCottagePage() {
  const [earned, setEarned]             = useState([]);
  const [cur, setCur]                   = useState(0);
  const [answer, setAnswer]             = useState([]);
  const [tiles, setTiles]               = useState([]);
  const [secs, setSecs]                 = useState(30);
  const [skyIdx, setSkyIdx]             = useState(0);
  const [sunBot, setSunBot]             = useState(38);
  const [msg, setMsg]                   = useState("");
  const [msgOk, setMsgOk]               = useState(false);
  const [showPostcard, setShowPostcard] = useState(true);
  const [showShare, setShowShare]       = useState(false);
  const [copied, setCopied]             = useState(false);
  const [revealed, setRevealed]         = useState({});
  const [celebrating, setCelebrating]   = useState(false);
  const [showHSH, setShowHSH]           = useState(false);
  const timerRef   = useRef(null);
  const fwRef      = useRef(null);
  const canvasRef  = useRef(null);
  const hasMounted = useRef(false);

  useEffect(() => {
    hasMounted.current = true;
    try {
      const saved = JSON.parse(localStorage.getItem(SAVE_KEY) || "[]");
      setEarned(saved);
      const first = PUZZLES.findIndex((_, i) => !saved.includes(i));
      const startIdx = first === -1 ? 0 : first;
      setCur(startIdx);
      setTiles(PUZZLES[startIdx].sc.split(""));
      if (saved.length === PUZZLES.length) startCelebration();
    } catch(e) {
      setTiles(PUZZLES[0].sc.split(""));
    }
  }, []);

  useEffect(() => {
    if (!hasMounted.current) return;
    setAnswer([]);
    setTiles(PUZZLES[cur].sc.split(""));
    setMsg("");
    resetSun();
  }, [cur]);

  function save(newEarned) {
    try { localStorage.setItem(SAVE_KEY, JSON.stringify(newEarned)); } catch(e) {}
  }

  function resetSun() {
    clearInterval(timerRef.current);
    setSecs(30); setSkyIdx(0); setSunBot(38);
    timerRef.current = setInterval(() => {
      setSecs(prev => {
        const next = prev - 1;
        const ratio = next / 30;
        setSkyIdx(ratio > 0.75 ? 0 : ratio > 0.5 ? 1 : ratio > 0.25 ? 2 : 3);
        setSunBot((ratio * 45) - 5);
        if (next <= 0) {
          clearInterval(timerRef.current);
          setMsg("The sun set! Hit Shuffle and try again.");
          setMsgOk(false);
        }
        return next;
      });
    }, 1000);
  }

  function stopSun() {
    clearInterval(timerRef.current);
    setSecs(30); setSkyIdx(0); setSunBot(38);
  }

  function startCelebration() {
    setCelebrating(true);
    setSkyIdx(3);
    setSunBot(-40);
    setShowHSH(false);
    const cv = canvasRef.current;
    if (!cv) return;
    cv.width  = cv.offsetWidth  || 160;
    cv.height = cv.offsetHeight || 90;
    const ctx = cv.getContext("2d");
    let particles = [];
    let bursts = 0;

    function launchBurst() {
      const x = 20 + Math.random() * (cv.width - 40);
      const y = 10 + Math.random() * (cv.height * 0.6);
      const colors = ["#ffdd57","#ff6b6b","#74ebd5","#f9a8d4","#ffffff","#ffa94d"];
      const col = colors[Math.floor(Math.random() * colors.length)];
      for (let i = 0; i < 18; i++) {
        const angle = (i / 18) * Math.PI * 2;
        const speed = 0.8 + Math.random() * 1.4;
        particles.push({ x, y, vx: Math.cos(angle)*speed, vy: Math.sin(angle)*speed, alpha:1, col, size:1.5+Math.random() });
      }
      bursts++;
      if (bursts < 8) setTimeout(launchBurst, 400 + Math.random() * 300);
      else setTimeout(() => setShowHSH(true), 800);
    }

    function draw() {
      ctx.clearRect(0, 0, cv.width, cv.height);
      particles.forEach(p => {
        p.x += p.vx; p.y += p.vy; p.vy += 0.04; p.alpha -= 0.018;
        if (p.alpha > 0) {
          ctx.globalAlpha = p.alpha;
          ctx.fillStyle = p.col;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
          ctx.fill();
        }
      });
      ctx.globalAlpha = 1;
      particles = particles.filter(p => p.alpha > 0);
      fwRef.current = requestAnimationFrame(draw);
    }

    launchBurst();
    draw();
  }

  function stopCelebration() {
    if (fwRef.current) cancelAnimationFrame(fwRef.current);
    setCelebrating(false);
    setShowHSH(false);
    setSkyIdx(0);
    setSunBot(38);
    const cv = canvasRef.current;
    if (cv) cv.getContext("2d").clearRect(0, 0, cv.width, cv.height);
  }

  function pick(ti, ch) {
    if (answer.filter(Boolean).length >= PUZZLES[cur].word.length) return;
    setAnswer(prev => [...prev, {ti, ch}]);
  }

  function unpick(si) {
    setAnswer(prev => prev.filter((_, i) => i !== si));
  }

  function doClear() { setAnswer([]); setMsg(""); }

  function doShuffle() {
    setTiles(prev => {
      const arr = [...prev];
      for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
      }
      return arr;
    });
    doClear();
  }

  function doCheck() {
    const guess = answer.map(a => a.ch).join("");
    const word  = PUZZLES[cur].word;
    if (guess.length < word.length) { setMsg("Fill in all the letters first!"); setMsgOk(false); return; }
    if (guess === word) {
      clearInterval(timerRef.current);
      const newEarned = earned.includes(cur) ? earned : [...earned, cur];
      setEarned(newEarned);
      save(newEarned);
      setRevealed(prev => ({ ...prev, [cur]: true }));
      setMsg("Placed in your cottage!");
      setMsgOk(true);
      stopSun();
      if (newEarned.length === PUZZLES.length) {
        setTimeout(() => { startCelebration(); }, 800);
        setTimeout(() => { setShowShare(true); }, 7500);
      }
    } else {
      setMsg("Not quite, try again!");
      setMsgOk(false);
      setAnswer([]);
    }
  }

  function doReset() {
    if (!confirm("Clear all progress and start fresh?")) return;
    try { localStorage.removeItem(SAVE_KEY); } catch(e) {}
    stopCelebration();
    setEarned([]); setRevealed({}); setCur(0);
    setAnswer([]); setTiles(PUZZLES[0].sc.split("")); setMsg("");
    stopSun();
  }

  function doCopy() {
    const text = `🏖️ Beach Cottage Decorator\n${'🐚'.repeat(earned.length)}\n${earned.length}/9 treasures\nlettergriddlecottage.com/beach\nMore games: lettergriddle.com`;
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    });
  }

  function doNativeShare() {
    navigator.share({
      text: `🏖️ Beach Cottage Decorator\n${'🐚'.repeat(earned.length)}\n${earned.length}/9 treasures\nlettergriddlecottage.com/beach\nMore games: lettergriddle.com`,
    }).catch(() => {});
  }

  function selectPuzzle(i) {
    setCur(i);
    setAnswer([]);
    setTiles(PUZZLES[i].sc.split(""));
    setMsg("");
  }

  const p = PUZZLES[cur];
  const isEarned = (i) => earned.includes(i) || revealed[i];

  const itemPositions = [
    { idx:0, extra:{ bottom:"20px", left:"50%", transform:`translateX(-50%) scale(${isEarned(0)?1:0.6})`, width:"56px", height:"56px", zIndex:8 } },
    { idx:1, extra:{ top:"108px", left:"12px" } },
    { idx:2, extra:{ top:"108px", left:"64px" } },
    { idx:3, extra:{ top:"102px", left:"116px" } },
    { idx:4, extra:{ top:"108px", right:"64px" } },
    { idx:5, extra:{ top:"160px", left:"12px" } },
    { idx:6, extra:{ top:"157px", left:"64px" } },
    { idx:7, extra:{ top:"160px", right:"64px" } },
    { idx:8, extra:{ top:"160px", right:"12px" } },
  ];

  const postcardLeft = (emojis, label, size="2.8rem") => (
    <div style={{flex:"1.1", background:"#d4ede8", display:"flex", alignItems:"center", justifyContent:"center", flexDirection:"column", gap:"12px", padding:"24px", borderRight:"1px dashed #bcaaa4", fontSize:size}}>
      {emojis.map((e,i) => <span key={i}>{e}</span>)}
      <div style={{fontSize:"0.55rem", color:"#5c4033", letterSpacing:"2px", marginTop:"6px"}}>{label}</div>
    </div>
  );

  return (
    <>
      <style>{`
        * { -webkit-tap-highlight-color: transparent; user-select: none; }
        body { margin: 0; }
        @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
        .hsh { animation: fadeIn 1.5s ease forwards; }
      `}</style>

      {/* Welcome Postcard */}
        {showPostcard && (
          <div style={{position:"fixed", top:0, left:0, right:0, bottom:0, width:"100vw", height:"100vh", background:"rgba(44,20,4,0.97)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:100, padding:"16px"}}>
            <div style={{maxWidth:"520px", width:"100%"}}>
              <div style={{background:"#fffdf4", border:"1px solid #c2b69d", borderRadius:"4px", boxShadow:"3px 3px 0 #c2b69d,6px 6px 0 #a89880", display:"flex", overflow:"hidden", minHeight:"340px"}}>
                {postcardLeft(["🏖️🌊🐚","☀️🦀⚓","🏮🧭🔥"], "BEACH COTTAGE")}
                <div style={{flex:"1", padding:"22px 22px 22px 24px", display:"flex", flexDirection:"column", justifyContent:"space-between", background:"#fffdf4"}}>
                  <div style={{alignSelf:"flex-end", width:"44px", height:"54px", background:"#e7dec2", border:"1px solid #bcaaa4", borderRadius:"2px", display:"flex", alignItems:"center", justifyContent:"center", fontSize:"1.2rem", boxShadow:"inset 0 0 0 2px #faf6ee"}}>🌴</div>
                  <hr style={{border:"none", borderTop:"1px dashed #bcaaa4", margin:"10px 0"}} />
                  <div style={{fontSize:"0.85rem", lineHeight:"1.9", color:"#3e2723", flex:1, paddingTop:"6px", fontFamily:"system-ui,sans-serif"}}>
                    Welcome to the<br/>
                    <strong style={{color:"#7c2d12"}}>Beach Cottage!</strong><br/><br/>
                    Unscramble each word to earn a treasure for your cottage. Enjoy your stay!
                  </div>
                  <div style={{fontSize:"0.72rem", color:"#78716c", lineHeight:"1.8", marginTop:"10px", borderTop:"1px dashed #bcaaa4", paddingTop:"8px", fontFamily:"system-ui,sans-serif"}}>
                    Questions during your stay?<br/>
                    <a href="mailto:lettergriddle@gmail.com" style={{color:"#d84315", textDecoration:"none"}}>lettergriddle@gmail.com</a>
                  </div>
                </div>
              </div>
              <button onClick={() => setShowPostcard(false)}
                style={{marginTop:"16px", width:"100%", background:"#d84315", color:"#fff", border:"none", padding:"13px", borderRadius:"25px", fontSize:"1rem", fontFamily:"inherit", cursor:"pointer", fontWeight:"bold", boxShadow:"2px 2px 0 #8b1a1a"}}>
                Check In 🏖️
              </button>
              <p style={{textAlign:"center", fontSize:"0.6rem", color:"#bcaaa4", marginTop:"10px", fontFamily:"system-ui,sans-serif"}}>✦ Beta Summer Days ✦</p>
            </div>
          </div>
        )}

        {/* Share Postcard */}
        {showShare && (
          <div style={{position:"fixed", top:0, left:0, right:0, bottom:0, width:"100vw", height:"100vh", background:"rgba(44,20,4,0.95)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:100, padding:"16px"}}>
            <div style={{maxWidth:"520px", width:"100%"}}>
              <div style={{background:"#fffdf4", border:"1px solid #c2b69d", borderRadius:"4px", boxShadow:"3px 3px 0 #c2b69d,6px 6px 0 #a89880", display:"flex", overflow:"hidden", minHeight:"320px"}}>
                {postcardLeft(["🏖️🌊","☀️🐚","🦀🔥"], "DECORATED!")}
                <div style={{flex:"1", padding:"22px 22px 22px 24px", display:"flex", flexDirection:"column", justifyContent:"space-between", background:"#fffdf4"}}>
                  <div style={{alignSelf:"flex-end", width:"44px", height:"54px", background:"#e7dec2", border:"1px solid #bcaaa4", borderRadius:"2px", display:"flex", alignItems:"center", justifyContent:"center", fontSize:"1.2rem", boxShadow:"inset 0 0 0 2px #faf6ee"}}>🏡</div>
                  <hr style={{border:"none", borderTop:"1px dashed #bcaaa4", margin:"10px 0"}} />
                  <div style={{fontSize:"0.85rem", lineHeight:"1.9", color:"#3e2723", flex:1, fontFamily:"system-ui,sans-serif"}}>
                    I decorated my<br/>
                    <strong style={{color:"#7c2d12"}}>Beach Cottage!</strong> ☀️<br/><br/>
                    Play at lettergriddlecottage.com/beach
                  </div>
                  <div style={{fontSize:"0.6rem", color:"#bcaaa4", marginTop:"8px", fontFamily:"system-ui,sans-serif", letterSpacing:"1px"}}>✦ Beta Summer Days ✦</div>
                </div>
              </div>
              <div style={{display:"flex", gap:"10px", marginTop:"14px"}}>
                <button onClick={doCopy} style={{flex:1, padding:"10px", background:copied?"#2e7d32":"#5c4033", color:"#fff", border:"none", borderRadius:"20px", fontSize:"0.85rem", fontFamily:"inherit", cursor:"pointer", fontWeight:"bold"}}>
                  {copied ? "✓ Copied!" : "📋 Copy"}
                </button>
                {typeof navigator !== "undefined" && navigator.share && (
                  <button onClick={doNativeShare} style={{flex:1, padding:"10px", background:"#d84315", color:"#fff", border:"none", borderRadius:"20px", fontSize:"0.85rem", fontFamily:"inherit", cursor:"pointer", fontWeight:"bold"}}>
                    ↗ Share
                  </button>
                )}
                <button onClick={() => setShowShare(false)} style={{flex:1, padding:"10px", background:"#bcaaa4", color:"#fff", border:"none", borderRadius:"20px", fontSize:"0.85rem", fontFamily:"inherit", cursor:"pointer"}}>
                  Close
                </button>
              </div>
            </div>
          </div>
        )}

      <div style={{fontFamily:"'Courier New',Courier,monospace", background:"#e7dec2", minHeight:"100vh", display:"flex", flexDirection:"column", alignItems:"center", padding:"20px"}}>
        {/* Game */}
        <div style={{background:"#faf6ee", border:"1px solid #c2b69d", borderRadius:"12px", padding:"16px", maxWidth:"500px", width:"100%", boxShadow:"0 8px 24px rgba(0,0,0,0.06)"}}>

          {/* Cottage Scene */}
          <div style={{background:"#5c4033", border:"8px solid #3e2723", height:"230px", borderRadius:"4px", position:"relative", marginBottom:"14px", overflow:"hidden", boxShadow:"inset 0 0 30px rgba(0,0,0,0.8)"}}>

            {/* Window with fireworks canvas */}
            <div style={{position:"absolute", top:"10px", left:"50%", transform:"translateX(-50%)", width:"160px", height:"90px", border:"4px solid #3e2723", overflow:"hidden", zIndex:2, transition:"background 1.5s ease", background:celebrating?"linear-gradient(to bottom,#1a0a2e,#8b1a1a)":SKY[skyIdx]}}>
              <div style={{position:"absolute", left:"50%", transform:"translateX(-50%)", bottom:`${celebrating?-40:sunBot}px`, width:"26px", height:"26px", background:"#ffb300", borderRadius:"50%", boxShadow:"0 0 12px #ffb300", transition:"bottom 1s linear"}} />
              <div style={{position:"absolute", bottom:0, width:"100%", height:"18px", background:"#1a3a5c", clipPath:"polygon(0% 100%,0% 60%,15% 40%,30% 55%,50% 30%,70% 50%,85% 35%,100% 55%,100% 100%)", zIndex:3}} />
              <canvas ref={canvasRef} style={{position:"absolute", top:0, left:0, width:"100%", height:"100%", zIndex:15, pointerEvents:"none"}} />
              {showHSH && (
                <div className="hsh" style={{position:"absolute", top:"50%", left:"50%", transform:"translate(-50%,-50%)", fontFamily:"'Courier New',monospace", fontSize:"9px", fontWeight:"bold", color:"rgba(255,240,200,0.95)", textAlign:"center", zIndex:20, pointerEvents:"none", whiteSpace:"nowrap", letterSpacing:"1px", textShadow:"0 0 4px rgba(255,180,50,0.8)"}}>
                  ~ Home Sweet Home ~
                </div>
              )}
            </div>

            {/* Shelves */}
            <div style={{position:"absolute", top:"108px", left:"8px", right:"8px", height:"7px", background:"#6d3a1f", borderRadius:"1px", zIndex:6, boxShadow:"0 2px 5px rgba(0,0,0,0.5)"}} />
            <div style={{position:"absolute", top:"164px", left:"8px", right:"8px", height:"7px", background:"#6d3a1f", borderRadius:"1px", zIndex:6, boxShadow:"0 2px 5px rgba(0,0,0,0.5)"}} />
            <div style={{position:"absolute", top:"108px", left:"8px", width:"5px", height:"63px", background:"#5c3018", zIndex:5}} />
            <div style={{position:"absolute", top:"108px", right:"8px", width:"5px", height:"63px", background:"#5c3018", zIndex:5}} />
            <div style={{position:"absolute", bottom:"18px", left:"50%", transform:"translateX(-50%)", width:"110px", height:"75px", background:"#7c2d12", borderTop:"5px solid #451a03", borderLeft:"3px solid #451a03", borderRight:"3px solid #451a03", zIndex:4}} />
            <div style={{position:"absolute", bottom:0, width:"100%", height:"18px", background:"#78716c", borderTop:"2px solid #44403c", zIndex:5}} />

            {/* Items */}
            {itemPositions.map(({idx, extra}) => (
              <img key={idx} src={PUZZLES[idx].img} alt={PUZZLES[idx].word}
                style={{position:"absolute", zIndex:10, width:"50px", height:"50px", objectFit:"contain", opacity:isEarned(idx)?1:0, transform:`scale(${isEarned(idx)?1:0.6})`, transition:"opacity 0.6s ease,transform 0.6s cubic-bezier(.34,1.56,.64,1)", ...extra}} />
            ))}
          </div>

          {/* Puzzle Panel */}
          <div style={{background:"#fdfcf7", border:"2px dashed #bcaaa4", borderRadius:"8px", padding:"12px"}}>

            {/* Nav */}
            <div style={{display:"flex", justifyContent:"center", flexWrap:"wrap", gap:"5px", marginBottom:"10px"}}>
              {PUZZLES.map((pz, i) => (
                <button key={i} onClick={() => selectPuzzle(i)}
                  style={{background:i===cur?"#d84315":"none", color:i===cur?"#fff":"#3e2723", border:"1px solid #bcaaa4", borderRadius:"20px", padding:"2px 8px", fontSize:"0.72rem", fontFamily:"inherit", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", minWidth:"30px", opacity:earned.includes(i)?0.6:1}}>
                  {earned.includes(i)
                    ? <img src={pz.img} alt={pz.word} style={{width:"26px", height:"26px", objectFit:"contain"}} />
                    : (i + 1)
                  }
                </button>
              ))}
            </div>

            {/* Sun bar */}
            <div style={{display:"flex", alignItems:"center", gap:"8px", marginBottom:"10px"}}>
              <span style={{fontSize:"14px"}}>☀️</span>
              <div style={{flex:1, height:"8px", background:"#3e2723", borderRadius:"4px", overflow:"hidden", border:"1px solid #6d3a1f"}}>
                <div style={{height:"100%", width:`${Math.max(0,Math.round((secs/30)*100))}%`, background:"#f59e0b", borderRadius:"4px", transition:"width 1s linear"}} />
              </div>
              <span style={{fontSize:"0.75rem", color:"#78716c", minWidth:"30px", textAlign:"right"}}>0:{String(Math.max(0,secs)).padStart(2,"0")}</span>
            </div>

            {/* Current item */}
            <div style={{display:"flex", alignItems:"center", gap:"12px", marginBottom:"10px", paddingBottom:"10px", borderBottom:"1px dashed #d7ccc8"}}>
              <img src={p.img} alt="mystery item" style={{width:"72px", height:"72px", objectFit:"contain", background:"#5c4033", borderRadius:"6px", padding:"5px"}} />
              <div>
                <div style={{fontSize:"0.78rem", color:"#78716c", fontStyle:"italic"}}>🌊 {p.hint}</div>
                {isEarned(cur) && (
                  <div style={{fontSize:"0.85rem", fontWeight:"bold", color:"#2e7d32", marginTop:"4px"}}>✓ {p.word}</div>
                )}
              </div>
            </div>

            {/* Slots */}
            <div style={{display:"flex", gap:"4px", justifyContent:"center", flexWrap:"wrap", marginBottom:"8px", minHeight:"42px"}}>
              {p.word.split("").map((_, i) => (
                <div key={i} onClick={() => unpick(i)}
                  style={{width:"34px", height:"34px", borderBottom:`2px solid ${isEarned(cur)?"#2e7d32":"#8B6340"}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:"13px", fontWeight:"bold", color:isEarned(cur)?"#2e7d32":"#3e2723", cursor:"pointer", fontFamily:"inherit"}}>
                  {answer[i]?.ch || ""}
                </div>
              ))}
            </div>

            {/* Tiles */}
            <div style={{display:"flex", gap:"4px", justifyContent:"center", flexWrap:"wrap", marginBottom:"10px", minHeight:"42px"}}>
              {tiles.map((ch, i) => (
                <button key={`${i}-${ch}`} onClick={() => pick(i, ch)}
                  disabled={answer.some(a => a.ti === i)}
                  style={{width:"34px", height:"34px", background:"#f5ede0", border:"1px solid #bcaaa4", borderRadius:"6px", fontSize:"13px", fontWeight:"bold", color:"#3e2723", cursor:"pointer", fontFamily:"inherit", opacity:answer.some(a=>a.ti===i)?0.2:1, pointerEvents:answer.some(a=>a.ti===i)?"none":"auto"}}>
                  {ch}
                </button>
              ))}
            </div>

            {/* Buttons */}
            <div style={{display:"flex", gap:"6px", justifyContent:"center", flexWrap:"wrap"}}>
              <button onClick={doClear}   style={{fontFamily:"inherit", fontSize:"0.8rem", padding:"6px 14px", borderRadius:"20px", cursor:"pointer", border:"1px solid #bcaaa4", background:"#fdfcf7", color:"#3e2723"}}>Clear</button>
              <button onClick={doShuffle} style={{fontFamily:"inherit", fontSize:"0.8rem", padding:"6px 14px", borderRadius:"20px", cursor:"pointer", border:"1px solid #bcaaa4", background:"#fdfcf7", color:"#3e2723"}}>Shuffle</button>
              <button onClick={doCheck}   style={{fontFamily:"inherit", fontSize:"0.8rem", padding:"6px 14px", borderRadius:"20px", cursor:"pointer", border:"none", background:"#d84315", color:"#fff", fontWeight:"bold"}}>Place it! 🔨</button>
              <button onClick={doReset}   style={{fontFamily:"inherit", fontSize:"0.85rem", padding:"8px 18px", borderRadius:"20px", cursor:"pointer", border:"none", background:"#d84315", color:"#fff", fontWeight:"bold", boxShadow:"0 2px 6px rgba(0,0,0,0.2)"}}>🔄 Reset Cottage</button>
            </div>

            <div style={{textAlign:"center", fontSize:"0.8rem", minHeight:"18px", marginTop:"8px", color:msgOk?"#2e7d32":"#c62828", fontWeight:msgOk?"bold":"normal"}}>
              {msg}
            </div>
            <div style={{fontSize:"0.75rem", color:"#bcaaa4", textAlign:"center", marginTop:"6px"}}>
              {earned.length === PUZZLES.length ? "🎉 Cottage fully decorated!" : `${earned.length} / ${PUZZLES.length} items placed`}
            </div>
          </div>

          {/* Footer */}
          <div style={{marginTop:"20px", textAlign:"center", fontSize:"0.7rem", color:"#78716c", fontFamily:"system-ui,sans-serif", lineHeight:"2"}}>
            <p style={{marginBottom:"8px"}}>
              <a href="https://lettergriddle.com" target="_blank" rel="noopener noreferrer"
                style={{background:"#d84315", color:"#fff", padding:"6px 16px", borderRadius:"20px", textDecoration:"none", fontWeight:"bold", fontSize:"0.75rem"}}>
                🥞 More Letter Griddle Games
              </a>
            </p>
            <p>© {new Date().getFullYear()} Letter Griddle</p>
            <div style={{display:"flex", justifyContent:"center", gap:"8px", marginTop:"4px", flexWrap:"wrap"}}>
              <Link href="/privacy" style={{color:"#78716c"}}>Privacy</Link>
              <span>|</span>
              <Link href="/terms" style={{color:"#78716c"}}>Terms</Link>
              <span>|</span>
              <a href="mailto:lettergriddle@gmail.com" style={{color:"#78716c"}}>Contact</a>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
